mapper.select:
SELECT * FROM tickets
WHERE project_id = #{projectId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
ORDER BY created_at DESC

SELECT * FROM tickets
WHERE project_id = #{projectId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
  AND stage = #{stage, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
ORDER BY priority, created_at DESC

SELECT * FROM tickets
WHERE project_id = #{projectId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
  AND type = #{type, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
ORDER BY created_at DESC

SELECT * FROM tickets
WHERE project_id = #{projectId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
  AND priority = #{priority, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
ORDER BY created_at DESC

SELECT * FROM tickets
WHERE assignee_id = #{assigneeId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
ORDER BY priority, due_date, created_at DESC

SELECT * FROM tickets
WHERE reporter_id = #{reporterId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
ORDER BY created_at DESC

SELECT COUNT(*) FROM tickets
WHERE project_id = #{projectId, typeHandler=com.runnershigh.tps.adapter.out.persistence.typehandler.UuidTypeHandler}
  AND stage = #{stage, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
